import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { EquippedLoadoutParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/EquippedLoadoutParser';

export class EquippedLoadoutEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, EquippedLoadoutParser);
        console.log('[🧰] EquippedLoadoutEvent initialized!');
    }

    public getParser(): EquippedLoadoutParser {
        return this.parser as EquippedLoadoutParser;
    }
}
